3_real_world_example.code:
class Player {
  #health = 100; // Encapsulated (hidden) data

  // Approved method to interact with the data
  takeDamage(amount) {
    if (amount < 0) return; // Prevent healing via damage!
    this.#health -= amount;
    if (this.#health < 0) this.#health = 0;
  }

  getHealth() {
    return this.#health;
  }
}

const p = new Player();
//  We cannot do p.#health = -50000; (State is protected)
p.takeDamage(30); //  We use the approved method
console.log(p.getHealth()); // 70

